function mistakePractice(){const items=reviewMistakes(),item=items[state.mistakeIndex]||items[0];if(!item)return `<div class="mistake-practice-page">${topbar('错题练习','mistakes')}<div class="empty-state"><b>还没有收藏</b><p>可以从面试报告或场景对话中加入语言问题。</p></div></div>`;const transcript=state.mistakeTranscripts[state.mistakeIndex]||'',hasTranscript=Boolean(transcript),isLast=state.mistakeIndex===items.length-1;const micIcon='<svg viewBox="0 0 24 24" aria-hidden="true"><rect x="9" y="3" width="6" height="11" rx="3"></rect><path d="M5.5 11.5a6.5 6.5 0 0 0 13 0M12 18v3M9 21h6"></path></svg>';const steps=`<div class="mistake-step-progress" style="--steps:${items.length}" role="progressbar" aria-label="第 ${state.mistakeIndex+1} 题，共 ${items.length} 题" aria-valuenow="${state.mistakeIndex+1}" aria-valuemin="1" aria-valuemax="${items.length}">${items.map((_,i)=>`<i class="${i<state.mistakeIndex?'done':i===state.mistakeIndex?'active':''}"></i>`).join('')}</div>`;return `<div class="mistake-practice-page">${topbar('错题练习','mistakes')}${steps}<main class="mistake-practice-scroll"><small class="mistake-voice-meta">${esc(item.type)} · ${esc(item.source)}</small><section class="mistake-voice-question"><h1>${esc(item.prompt||item.title)}</h1><p>${esc(item.original)}</p><button class="mistake-audio-link" data-action="bubble-audio">▶ 播放原句</button></section>${state.mistakeRecording?`<section class="mistake-listening-state"><div class="mistake-voice-wave" aria-hidden="true">${'<i></i>'.repeat(9)}</div><h2>正在聆听…</h2><p>用英语重新说一遍，完成后点击下方按钮。</p></section>`:hasTranscript?`<section class="mistake-spoken-answer"><small>我说的 · 自动转写</small><p>${esc(transcript)}</p></section>${state.mistakeRevealed?`<section class="mistake-voice-feedback"><small>推荐表达</small><h2>${esc(item.recommended)}</h2><p>${item.explanation}</p><button class="mistake-audio-link" data-action="bubble-audio">▶ 听推荐表达</button></section>`:`<p class="mistake-transcript-hint">确认转写无误后查看解析；如果表达不满意，可以重新说。</p>`}`:`<section class="mistake-voice-prompt"><div class="mistake-voice-wave idle" aria-hidden="true">${'<i></i>'.repeat(7)}</div><h2>请用英语重新说一遍</h2><p>不需要逐字照搬，先把意思表达清楚。</p></section>`}</main><footer class="mistake-practice-actions">${state.mistakeRecording?`<button class="mistake-record-action recording" data-action="mistake-record"><span class="mistake-stop-icon"></span>完成回答</button>`:state.mistakeRevealed?`<button class="mistake-action-secondary" data-action="mistake-retry">再说一次</button><button class="mistake-action-primary" data-action="next-mistake">${isLast?'完成复习':'下一题'}</button>`:hasTranscript?`<button class="mistake-action-secondary" data-action="mistake-retry">重新说</button><button class="mistake-action-primary" data-action="reveal-mistake">查看解析</button>`:`<button class="mistake-record-action" data-action="mistake-record">${micIcon}<span>点击说英语</span></button>`}</footer></div>`}
function mistakeComplete(){const count=reviewMistakes().length,minutes=Math.max(1,Math.ceil(count*.8));return `<div class="mistake-complete-page">${topbar('复盘完成','mistakes')}<section class="mistake-complete"><span class="complete-mark">✓</span><small>本轮已完成</small><h1>${count} 道错题<br>全部复盘完成</h1><p>你已经重新练习了本次选择的语言问题。答案会保留到下次进入前。</p><div class="complete-stats"><span><b>${count}</b><small>已复习</small></span><span><b>${new Set(reviewMistakes().map(item=>item.type)).size}</b><small>问题类型</small></span><span><b>${minutes} 分钟</b><small>预计用时</small></span></div><button class="primary btn-wide" data-action="start-mistakes" data-mistake-scope="all">再练一轮</button><button class="secondary btn-wide" data-route="home">返回练习记录</button></section></div>`}
