state.sessionsByInterviewer[1][0].retryAttempts={0:[],1:[],2:[],3:[]};
state.sessionsByInterviewer[1][0].ts=Date.now()-120000;
state.plans=[{id:'plan-backend-1',snapshot:state.planSnapshot,interviewers:state.interviewers,sessions:state.sessionsByInterviewer}];
state.activePlanId='plan-backend-1';
state.plans=[];
state.activePlanId=null;
state.planSnapshot=null;
state.sessionsByInterviewer=state.interviewers.map(()=>[]);
state.activeSessionId=null;
state.turnTranscripts=[];
state.dynamicQuestions=[];
state.interviewChatOpen=false;
const activePlanRecord=()=>state.plans.find(x=>x.id===state.activePlanId);
const activatePlan=id=>{const plan=state.plans.find(x=>x.id===id);if(!plan)return;state.activePlanId=id;state.planSnapshot=plan.snapshot;state.interviewers=plan.interviewers;state.sessionsByInterviewer=plan.sessions;state.activeInterviewer=0;state.activeSessionId=plan.sessions.flat()[0]?.id||null};
const sessionRetries=()=>{const session=activeSession();if(!session)return state.retryAttempts;if(!session.retryAttempts)session.retryAttempts={0:[],1:[],2:[],3:[]};return session.retryAttempts};
const quoteFromTranscript=text=>{const words=String(text||'').trim().split(/\s+/);const excerpt=words.slice(0,16).join(' ');return `“${excerpt}${words.length>16?'…':''}”`};
const feedbackTargets=[
  '补充项目规模、业务边界和你负责的服务范围。',
  '补充你亲自完成的代码、决策和协作边界。',
  '补充比较过的替代方案、选择依据和代价。',
  '补充验证环境、失败场景、结果和容量边界。'
];
const hrFeedbackTargets=[
  '补充一项与目标岗位直接相关的优势或成果。',
  '更具体地说明离职原因，并避免只描述对现公司的不满。',
  '补充你如何确认双方达成一致，以及最终结果。',
  '把职业目标与该岗位的成长路径连接起来。'
];
const feedbackTargetsForRound=()=>isHrRound()?hrFeedbackTargets:feedbackTargets;
const syncFeedbackFromTranscripts=()=>{const session=activeSession();if(session?.feedbackItems){ms1Feedback.splice(0,ms1Feedback.length,...session.feedbackItems.map(item=>({...item})));return}const items=ms1Feedback.map((_,i)=>{const transcript=state.turnTranscripts[i]||transcriptsForRound()[i],complete=isHrRound()?[true,false,true,false][i]:transcript.trim().split(/\s+/).length>=16;return {status:complete?'证据完整':'需要补充',quote:quoteFromTranscript(transcript),diagnosis:complete?(isHrRound()?'回答直接回应了问题，并提供了清晰、可核对的个人信息。':'回答提供了可核对的项目细节，引用内容来自本场实际转录。'):(isHrRound()?'回答方向正确，但与岗位匹配或个人选择相关的依据还不够具体。':'当前回答的可核对细节不足，需要继续补充与本题目标直接相关的事实。'),target:feedbackTargetsForRound()[i]}});ms1Feedback.splice(0,ms1Feedback.length,...items);if(session)session.feedbackItems=items.map(item=>({...item}))};

function ms1Auth(){return `<div class="auth-page"><div class="auth-logo" aria-hidden="true">S</div><h1>AI 英语口语陪练<br>海外求职，开口即练</h1><p>模拟面试 · 场景对话 · 实时纠错 · 同题复练</p><div class="auth-tabs"><button class="${state.authMode==='login'?'active':''}" data-action="auth-mode" data-mode="login">登录</button><button class="${state.authMode==='register'?'active':''}" data-action="auth-mode" data-mode="register">注册</button></div><form class="auth-form" id="ms1-auth"><label>邮箱<input class="field" name="email" type="email" value="demo@speakup.ai" required></label><label>密码<input class="field" name="password" type="password" value="speakup123" minlength="8" required></label>${state.authMode==='register'?'<label>确认密码<input class="field" name="confirm" type="password" value="speakup123" minlength="8" required></label>':''}${state.authError?`<div class="form-error">${state.authError}</div>`:''}<button class="primary btn-wide" type="submit">${state.authMode==='login'?'登录并继续':'创建账户'}</button></form></div>`}
function ms1Home(){const plan=state.planSnapshot,started=state.sessionsByInterviewer.filter(x=>x.length).length,completed=state.sessionsByInterviewer.flat().filter(x=>x.status==='completed').length,retries=Object.values(state.retryAttempts).flat().length,recentIndex=state.sessionsByInterviewer[state.activeInterviewer]?.length?state.activeInterviewer:state.sessionsByInterviewer.findIndex(x=>x.length),recent=recentIndex>=0?state.sessionsByInterviewer[recentIndex][0]:null,recentName=recentIndex>=0?state.interviewers[recentIndex]?.name:'';return `<div class="history-page"><header class="history-head"><div><small>INTERVIEW HISTORY</small><h1>面试历史</h1><p>按计划查看每位面试官的独立场次、报告与复练版本。</p></div><span class="history-count">${plan?'1':'0'} 个计划</span></header>${plan?`<section class="history-overview"><div><small>已开始</small><b>${started} 位</b></div><div><small>已完成场次</small><b>${completed} 场</b></div><div><small>复练版本</small><b>${retries} 个</b></div></section><section class="history-list"><button class="history-card interview" data-route="rounds"><span class="history-art interview-icon"><svg viewBox="0 0 24 24" width="24" height="24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M12 2a3 3 0 0 1 3 3v6a3 3 0 0 1-6 0V5a3 3 0 0 1 3-3Z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="22"/><line x1="8" y1="22" x2="16" y2="22"/></svg></span><span class="history-copy"><small>面试计划 · 项目深挖</small><strong>${esc(plan.jobName)}</strong><em><span class="recent-person">${esc(recentName)}</span><span>${recent?.time||'暂无时间'}，${recent?.status==='completed'?'已完成':`第 ${Math.min((recent?.currentTurn||0)+1,4)} 问进行中`}</span></em><span class="history-progress"><i style="width:${Math.min(((recent?.currentTurn||0)/4)*100,100)}%"></i></span></span><span class="history-open">查看</span></button></section><div class="ms1-note">计划使用已确认的经历快照；以后修改或删除简历，不会改变历史报告。</div>`:'<div class="empty-state"><b>还没有面试计划</b><p>填写目标岗位并确认一条经历后，即可开始项目深挖面试。</p><button class="primary btn-wide" data-route="create-job">创建面试计划</button></div>'}</div>`}
function ms1CreateHub(){const prompts=['Why this role?','What did you own?','Show me the code.','How does it scale?'];return `<div class="tab-page create-hub"><h1>开始一个练习</h1><section class="create-feature interviewer-cover"><div class="cover-glow"></div><div class="create-cast interview-cast">${prompts.map((prompt,i)=>`<div class="cast-person cast-person-${i}">${characterAvatar(i)}<span class="cast-speech">${prompt}</span></div>`).join('')}</div><div class="create-feature-copy"><span><strong>模拟面试</strong><small>项目深挖 · 4 次语音问答</small></span><button class="primary-dark" data-route="create-job">开始面试</button></div></section><h2>或试试场景口语</h2><section class="create-feature role-create-feature"><div class="role-card-art">${characterAvatar(5,true)}</div><div class="create-feature-copy"><span><strong>场景练习</strong><small>告诉 SpeakUp 你想练什么</small></span><button class="primary-dark" data-route="role-create">开始练习</button></div></section></div>`}
function ms1CreatePlan(){const d=state.interviewDraft,x=ms1Experiences[state.selectedExperience];return `${topbar('创建一个模拟面试','create-job')}${steps(2)}<h2>职位</h2><div class="summary-card editable-summary"><label>职位名称</label><input class="summary-edit-title" data-draft="jobName" value="${esc(d.jobName)}"><label>职位描述</label><textarea class="summary-edit-copy" data-draft="jobDescription">${esc(d.jobDescription)}</textarea></div><div class="section-title">我的简历</div><button class="resume-select active" data-route="resumes"><div class="resume-icon">PDF</div><div><h3>产品经理简历.pdf</h3><p>默认简历 · 可用 · 已识别 3 条经历</p><span>切换或上传　›</span></div></button><label class="field-label">确认本次面试经历</label>${ms1Experiences.map((e,i)=>`<button class="experience-option ${i===state.selectedExperience?'active':''}" data-action="select-experience" data-index="${i}"><i></i><span><b>${e.title}</b><small>${e.type} · ${e.date}</small></span></button>`).join('')}<div class="snapshot-card"><div class="section-title" style="margin:0 0 10px">经历快照</div><p><b>项目背景</b>${x.background}</p><p><b>个人职责</b>${x.role}</p><p><b>识别成果</b>${x.result}</p><button class="secondary btn-wide" data-action="edit-experience">编辑背景、职责与成果</button></div><label class="field-label">想重点练什么范围</label><input class="field" data-draft="focusScope" value="${esc(d.focusScope)}"><label class="field-label">补充要求（选填）</label><input class="field" data-draft="requirements" value="${esc(d.requirements)}"><div class="sticky-actions"><button class="secondary" data-route="create-job">返回</button><button class="primary" data-route="interviewers">生成面试官</button></div>`}
function ms1Interviewers(){return `${topbar('确认面试官','create-plan','<span class="chip">1-4 位</span>')}${steps(3)}<p style="color:var(--muted)">默认生成 4 位。每位对应独立面试，可编辑姓名、职责、风格和关注点。</p>${state.interviewers.map((p,i)=>`<div class="interviewer ms1-interviewer"><span class="face ${i===0?'green':i===2?'yellow':''}">•ᴗ•</span><span class="ms1-edit"><input data-person="name" data-index="${i}" value="${esc(p.name)}" aria-label="姓名"><input data-person="role" data-index="${i}" value="${esc(p.role)}" aria-label="职责"><input data-person="style" data-index="${i}" value="${esc(p.style)}" aria-label="风格"><input data-person="focus" data-index="${i}" value="${esc(p.focus)}" aria-label="关注点"></span><button class="remove" data-action="remove-interviewer" data-index="${i}" aria-label="删除">×</button></div>`).join('')}<button class="secondary btn-wide" data-action="add-interviewer" ${state.interviewers.length>=4?'disabled':''}>＋ 添加面试官</button>${state.interviewers.length===0?'<div class="form-error">至少保留 1 位面试官。</div>':''}<div class="sticky-actions"><button class="secondary" data-route="create-plan">返回</button><button class="primary" data-route="rounds" ${state.interviewers.length===0?'disabled':''}>保存面试计划</button></div>`}
function ms1Rounds(){return `<div class="rounds-page">${topbar('项目深挖面试','home')}<div class="round-summary"><span>经历　<b>SpeakUp 项目</b></span><span>面试官　<b>${state.interviewers.length} 位</b></span></div>${state.interviewers.map((p,i)=>`<section class="interviewer" style="grid-template-columns:56px 1fr auto"><span class="face ${i===0?'green':i===2?'yellow':''}">•ᴗ•</span><span><h3>${p.name} · ${p.role}</h3><p>${p.style} · ${p.focus}</p><em class="session-state ${p.status==='已完成'?'done':p.status==='进行中'?'active':''}">${p.status}${p.status==='已完成'?' · 2 场记录':p.status==='进行中'?' · 第 3/4 问':' · 尚无场次'}</em></span><button class="${p.status==='未开始'?'primary':'secondary'}" data-action="open-interviewer" data-index="${i}">${p.status==='未开始'?'开始':p.status==='进行中'?'继续':'报告 / 再练'}</button></section>`).join('')}<div class="ms1-note">不同面试官共享岗位与经历快照，但进度、问答、报告和复练历史互不覆盖。</div>`}
function ms1Mic(){const p=state.interviewers[state.activeInterviewer]||state.interviewers[0];return `${topbar('开始前检查','rounds')}<div class="mic-check">${characterAvatar(state.activeInterviewer||0,true)}<h2>${p?.name||'Mia'}</h2><p style="color:var(--muted)">项目深挖面试 · 完成一次短试音；试音不会保存。</p><div class="mic-meter ${state.recording?'on':''}">${'<i></i>'.repeat(9)}</div><h3>${state.micReady?'声音清晰，可以开始':'请说一句英文完成试音'}</h3>${state.micError?`<div class="form-error">${state.micError}</div><button class="secondary btn-wide" data-action="retry-mic">重新检测</button>`:`<button class="${state.micReady?'secondary':'primary'} btn-wide mic-btn-test" data-action="mic-test">${state.recording?'正在检测…':state.micReady?'重新试音':'开始试音'}</button>`}<button class="primary btn-wide mic-btn-enter" data-action="start-interview" ${state.micReady?'':'disabled'}>进入面试</button>${state.micHelpOpen?'<div class="repair-guide"><b>修复步骤</b><p>在浏览器地址栏允许麦克风权限。</p><p>在系统声音设置中选择正确的输入设备。</p><p>确认输入音量后重新试音。</p></div>':''}</div>`}
function ms1Practice(){const p=state.interviewers[state.activeInterviewer]||state.interviewers[0],turn=Math.min(state.interviewTurn,3),phase=state.interviewPhase;return `<div class="practice"><div class="practice-head"><button class="ghost-icon" data-route="rounds">‹</button><h1>项目深挖</h1><span class="chip">${turn+1} / 4</span></div><div class="turn-progress">${ms1Questions.map((_,i)=>`<i class="${i<=turn?'active':''}"></i>`).join('')}</div><div class="voice-state"><span class="face ${state.activeInterviewer===0?'green':''}">•ᴗ•</span><h2>${phase==='ai'?'AI 提问中':phase==='user'?'用户回答中':'AI 处理中'}</h2><p>${phase==='ai'?'你可以开口打断，未播放内容不会进入历史':phase==='user'?'请用英文回答；AI 不会在你说话时抢话':'正在保存音频并生成可用转录'}</p></div><div class="question-card"><small class="question-label">${['项目概览','个人贡献','方案取舍','验证与结果'][turn]}</small>${ms1Questions[turn]}<small>${phase==='ai'?'正在播放 · 已播放内容会保留':''}</small></div>${phase==='user'?'<div class="transcript"><b>实时转录</b><br>I owned the product definition and worked with design and engineering...</div>':''}<div class="practice-controls"><button class="round-btn" data-action="replay-question">↻</button><button class="talk ${phase==='user'?'recording':''}" data-action="ms1-answer">${phase==='user'?'提交回答':'开口回答'}</button><button class="round-btn" data-action="end-early">结束</button></div><p style="color:var(--muted);font-size:11px">空白、过短或识别失败不增加次数；断线后保留当前问题并重答。</p></div>`}
function ms1Report(){return `${topbar('面试报告总结','rounds')}<h1 class="hero-title">面试报告 <small style="font-size:14px">2026.07.14</small></h1><div class="metric-row"><div class="metric"><small>面试用时</small><b>30 分钟</b></div><div class="metric"><small>目标完成</small><b>4 / 4</b></div></div><div class="report-hero"><h3>总结</h3><p>项目背景与结果表达清楚。下一次重点补充个人决策和方案取舍依据。</p></div>${ms1Feedback.map((f,i)=>`<article class="evidence-card"><header><span><small>第 ${i+1} 问 · ${['项目概览','个人贡献','方案取舍','验证与结果'][i]}</small><h3>${ms1Questions[i]}</h3></span><em class="evidence-status ${f.status==='证据完整'?'complete':''}">${f.status}</em></header><button class="audio-protected" data-action="protected-audio">▶ <span><b>回听原回答</b><small>受保护音频 · 01:${32+i*8}</small></span></button><p><b>完整转录</b><br>${['I led the SpeakUp project for job seekers who struggled to explain real experience in English.','I owned the product definition and worked with design and engineering.','We decided not to use a generic score because users needed actionable evidence.','We tested the flow and task completion improved by 18 percent.'][i]}</p><blockquote>${f.quote}</blockquote><p><b>诊断</b><br>${f.diagnosis}</p><div class="retry-goal"><b>下一次改进目标</b><br>${f.target}</div><button class="primary btn-wide" data-action="open-retry" data-index="${i}">同题复练</button>${i===1?'<button class="version-row" data-action="toggle-versions"><span><b>全部回答版本</b><small>原回答 + 2 次复练，均保留独立原音</small></span><b>›</b></button>':''}</article>`).join('')}`}
function ms1Retry(){const i=state.reportExpanded||1,f=ms1Feedback[i];return `${topbar('同题复练','report','<span class="chip">第 ${state.retryCount+1} 次</span>')}<div class="question-card"><small>原问题</small>${ms1Questions[i]}</div><div class="retry-goal" style="margin:16px 0"><b>本次只检查这个缺口</b><br>${f.target}</div>${state.retryRecording?'<div class="transcript"><b>新回答转录</b><br>I compared a generic score with evidence cards, then chose the latter after five users could not act on a single score...</div>':''}<div class="practice-controls"><button class="talk ${state.retryRecording?'recording':''}" data-action="retry-record">${state.retryRecording?'提交新回答':'点击说话'}</button></div><p style="color:var(--muted);font-size:12px;text-align:center">每次复练创建新版本，不覆盖原回答或更早版本。</p>${state.showVersions?`<div class="retry-result"><div><small>已补充</small><b>✓ 替代方案：generic score<br>✓ 判断依据：用户无法据此行动</b></div><div><small>仍缺少</small><b>○ 说明比较发生在项目哪个阶段</b></div></div><button class="primary btn-wide" data-action="retry-again">再次复练</button><button class="secondary btn-wide" data-route="report">返回报告</button>`:''}`}
function ms1Profile(){return `<div class="tab-page mine-page"><div class="profile-top"><button class="avatar space-avatar">${characterAvatar(0,true)}</button><h1>不鸽offer</h1><p style="color:var(--muted)">${esc(state.authEmail)}</p></div><div class="profile-card"><button class="settings-row" data-route="resumes"><span class="settings-copy"><b>个人简历</b><small>管理简历文件与解析结果</small></span><span>${state.resumeCount} / 3　›</span></button><button class="settings-row" data-route="settings"><span class="settings-copy"><b>设置</b><small>账号、安全与隐私</small></span><span>›</span></button></div><div class="ms1-note">个人简历、报告与音频仅在登录状态下可访问；退出后受保护页面会返回登录。</div></div>`}
function ms1Resumes(){return `${topbar('个人简历','profile','<span class="chip">2 / 3</span>')}<p class="page-intro">仅支持 PDF，单份最大 10 MB；最多保存 3 份。</p><section class="resume-card active"><div class="resume-icon">PDF</div><div><h3>产品经理简历.pdf</h3><p>1.8 MB · 更新于今天</p><span class="resume-state">默认 · 可用</span></div><button data-action="resume-menu">•••</button></section><section class="resume-card"><div class="resume-icon">PDF</div><div><h3>校园版简历.pdf</h3><p>2.1 MB · 更新于昨天</p><span class="resume-state ${state.resumeStatus==='解析失败'?'fail':''}">${state.resumeStatus}</span></div><button data-action="resume-menu">•••</button></section>${state.resumeStatus==='解析失败'?'<div class="ms1-note">未识别到有效经历。可以重试解析，或手动填写经历继续创建面试。</div><button class="secondary btn-wide" data-action="manual-experience">手动填写经历</button>':''}<button class="resume-upload" data-action="upload-resume"><b>＋</b><span>上传一份新简历<small>支持 PDF，最大 10 MB</small></span></button><div class="ms1-note">状态：上传中 → 解析中 → 可用；失败时会显示具体原因与重试入口。</div>`}
function ms1Settings(){return `${topbar('设置','profile')}<div class="profile-card"><button class="settings-row"><span>头像</span><span class="avatar">${characterAvatar(0)}</span></button><button class="settings-row"><span>昵称</span><span>不鸽offer　›</span></button><div class="settings-row"><span>登录邮箱</span><span>${esc(state.authEmail)}</span></div></div><div class="profile-card"><button class="settings-row"><span>隐私政策</span><span>›</span></button><button class="settings-row"><span>关于产品</span><span>›</span></button></div><button class="secondary btn-wide" data-action="logout">退出登录</button><button class="danger btn-wide" style="margin-top:10px" data-action="delete-account">注销账号</button>${state.dialogPanel==='delete'?`<div class="sheet"><div class="sheet-card"><h2>永久注销账号？</h2><p>将删除账户、简历、解析结果、经历、计划、面试官、场次、音频、转录、报告、反馈与全部复练记录，且无法恢复。</p>${state.deleteError?`<div class="form-error">${state.deleteError}</div>`:''}<label class="confirm-line"><input type="checkbox" data-action="confirm-delete" ${state.deleteConfirmed?'checked':''}> 我已了解并确认删除全部数据</label><button class="danger btn-wide" data-action="delete-final" ${state.deleteConfirmed&&!state.deletePending?'':'disabled'}>${state.deletePending?'正在删除…':state.deleteError?'重试永久注销':'确认永久注销'}</button><button class="secondary btn-wide" data-action="close-delete">取消</button></div></div>`:''}`}

function alignedAuth(){return `<div class="auth-page"><div class="auth-logo" aria-hidden="true">S</div><h1>AI 英语口语陪练<br>海外求职，开口即练</h1><p>模拟面试 · 场景对话 · 实时纠错 · 同题复练</p><div class="auth-tabs"><button class="${state.authMode==='login'?'active':''}" data-action="auth-mode" data-mode="login">登录</button><button class="${state.authMode==='register'?'active':''}" data-action="auth-mode" data-mode="register">注册</button></div><form class="auth-form" id="ms1-auth"><label>邮箱<input class="field" name="email" type="email" value="${esc(state.authEmail)}" autocomplete="email" required></label><label>密码<input class="field" name="password" type="password" value="${esc(state.authPassword)}" minlength="8" autocomplete="current-password" required></label>${state.authMode==='register'?`<label>确认密码<input class="field" name="confirm" type="password" value="${esc(state.authPassword)}" minlength="8" autocomplete="new-password" required></label>`:''}${state.authError?`<div class="form-error">${state.authError}</div>`:''}<button class="primary btn-wide" type="submit" ${state.authSubmitting?'disabled':''}>${state.authSubmitting?'正在连接…':state.authMode==='login'?'登录并继续':'创建账户'}</button></form></div>`}

const activeResume=()=>state.resumeItems[state.selectedResumeIndex]||state.resumeItems[state.defaultResume]||state.resumeItems[0];
function alignedCreatePlan(){const d=state.interviewDraft,x=ms1Experiences[state.selectedExperience],resume=activeResume(),resumeReady=state.manualExperience||resume?.status==='可用',experienceReady=Boolean(x?.title.trim()&&x?.background.trim()&&x?.role.trim()&&x?.result.trim()),canGenerate=Boolean(d.jobName.trim()&&resumeReady&&experienceReady&&state.generateStatus!=='loading'),atLimit=state.resumeItems.length>=3,failed=item=>['解析失败','内容为空'].includes(item.status),activeItem=state.resumeItems[state.selectedResumeIndex??state.defaultResume]||state.resumeItems[0],exps=activeItem?.experienceData||[],hasContent=activeItem&&(activeItem.manualData||(exps.length>0)),menuItem=state.resumeItems[state.resumeMenuIndex];return `${topbar('创建一个模拟面试','create-job')}${steps(2)}<h2>职位</h2><div class="summary-card editable-summary"><label>职位名称</label><input class="summary-edit-title" data-draft="jobName" value="${esc(d.jobName)}" required><label>职位描述</label><textarea class="summary-edit-copy" data-draft="jobDescription">${esc(d.jobDescription)}</textarea></div><div class="resume-methods"><button class="resume-method" data-action="upload-resume" ${atLimit?`disabled`:` `}><span class="method-icon"><svg viewBox="0 0 24 24" width="22" height="22" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg></span><strong>上传简历</strong><small>PDF 格式，最大 10 MB</small></button><button class="resume-method" data-action="write-resume" ${atLimit?`disabled`:` `}><span class="method-icon"><svg viewBox="0 0 24 24" width="22" height="22" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg></span><strong>编写简历</strong><small>手动填写项目经历</small></button></div><div class="resume-list">${state.resumeItems.map((item,i)=>`<section class="resume-card ${i===state.defaultResume?`active`:``} ${failed(item)?`failed`:``}"><div class="resume-main"><div class="resume-icon"><svg viewBox="0 0 24 24" width="22" height="22" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8Z"/><path d="M14 2v6h6"/><path d="M16 13H8"/><path d="M16 17H8"/><path d="M10 9H8"/></svg></div><div class="resume-info"><h3>${esc(item.name)}</h3><p>${item.size}${item.experiences?` · ${item.experiences} 条经历`:``}</p><div class="resume-badges"><span class="resume-state ${failed(item)||item.status===`上传失败`?`fail`:``}">${i===state.defaultResume?`默认 · `:``}${item.status}</span></div></div><button class="ghost-icon" data-action="resume-menu" data-index="${i}">⋯</button></div>${item===activeItem&&hasContent?(item.manualData?renderManualSections(item):``):``}</section>`).join(``)}</div>${state.resumeError?`<div class="form-error">${state.resumeError}</div>`:``}<label class="field-label">练习重点</label><div class="focus-topics">${[`项目深挖`,`系统设计`,`技术原理`,`编码能力`,`行为面试`,`沟通表达`].map((t,i)=>`<button class="focus-chip ${state.focusTopics[i]?`active`:``}" data-action="toggle-focus-topic" data-index="${i}">${t}</button>`).join(``)}</div><label class="field-label">补充要求（选填）</label><input class="field" data-draft="requirements" value="${esc(d.requirements)}">${state.generateError?`<div class="form-error">${state.generateError}</div>`:''}<div class="sticky-actions"><button class="secondary" data-route="create-job">返回</button><button class="primary" data-action="generate-interviewers" ${canGenerate?'':'disabled'}>${state.generateStatus==='loading'?'正在生成…':state.generateError?'重新生成':'生成面试官'}</button></div>${menuItem?`<div class="sheet"><div class="sheet-card"><div class="topbar"><h2>简历操作</h2><button class="ghost-icon" data-action="close-resume-menu">×</button></div>${state.resumeRenaming?`<div class="exp-field"><label>简历名称</label><input data-resume-rename value="${esc(menuItem.name)}" placeholder="请输入简历名称"></div><div class="exp-card-actions"><button data-action="cancel-rename-resume">取消</button><button class="primary" data-action="save-rename-resume" data-index="${state.resumeMenuIndex}">保存</button></div>`:`<strong>${esc(menuItem.name)}</strong><button class="secondary btn-wide" data-action="rename-resume">重命名</button><button class="secondary btn-wide" data-action="set-default-resume" data-index="${state.resumeMenuIndex}" ${state.resumeMenuIndex===state.defaultResume?'disabled':''}>设为默认简历</button><button class="danger btn-wide" data-action="delete-resume" data-index="${state.resumeMenuIndex}">删除这份简历</button><p class="snapshot-footnote">删除不会改变已有面试计划和历史报告中的文本快照。</p>`}</div></div>`:''}`}

function alignedResumes(){const atLimit=state.resumeItems.length>=3,menuItem=state.resumeItems[state.resumeMenuIndex];return `${topbar('个人简历',state.resumeReturnRoute||'profile',`<span class="chip">${state.resumeItems.length} / 3</span>`)}<p class="page-intro">仅支持便携式文档格式，单份最大十兆字节；解析结果同时包含项目与实习或工作经历。</p>${state.resumeItems.map((item,i)=>`<section class="resume-card ${i===state.defaultResume?'active':''}"><div class="resume-icon">PDF</div><div><h3>${esc(item.name)}</h3><p>${item.size}${item.experiences?` · ${item.experiences} 条经历`:''}</p><span class="resume-state ${item.status==='解析失败'||item.status==='上传失败'||item.status==='内容为空'?'fail':''}">${i===state.defaultResume?'默认 · ':''}${item.status}</span></div><button data-action="resume-menu" data-index="${i}" aria-label="简历操作">•••</button>${state.resumeReturnRoute==='create-plan'&&item.status==='可用'?`<button class="resume-use" data-action="use-resume" data-index="${i}">${i===state.defaultResume?'已选择':'使用'}</button>`:''}</section>`).join('')}${!state.resumeItems.length?'<div class="empty-state"><b>还没有简历</b><p>上传一份简历后，系统会提取项目和实习经历。</p></div>':''}${state.resumeError?`<div class="form-error">${state.resumeError}</div><button class="secondary btn-wide" data-action="clear-resume-error">重新选择文件</button>`:''}${state.resumeItems.some(x=>x.status==='解析失败'||x.status==='内容为空')?'<div class="form-error">未识别到有效经历。可以重试解析，或手动填写经历继续创建面试。</div><div class="sticky-actions"><button class="secondary" data-action="retry-resume">重试解析</button><button class="primary" data-action="manual-experience">手动填写</button></div>':''}<button class="resume-upload" data-action="upload-resume" ${atLimit?'disabled':''}><b>${state.resumeItems.some(x=>x.status==='上传中'||x.status==='解析中')?'…':'＋'}</b><span>${atLimit?'已达到 3 份上限':state.resumeItems.some(x=>x.status==='上传中')?'正在上传简历文件':state.resumeItems.some(x=>x.status==='解析中')?'正在解析经历':'上传一份新简历'}<small>${atLimit?'请先删除一份再上传':'仅支持便携式文档格式，最大十兆字节'}</small></span></button>${menuItem?`<div class="sheet"><div class="sheet-card"><div class="topbar"><h2>简历操作</h2><button class="ghost-icon" data-action="close-resume-menu">×</button></div>${state.resumeRenaming?`<div class="exp-field"><label>简历名称</label><input data-resume-rename value="${esc(menuItem.name)}" placeholder="请输入简历名称"></div><div class="exp-card-actions"><button data-action="cancel-rename-resume">取消</button><button class="primary" data-action="save-rename-resume" data-index="${state.resumeMenuIndex}">保存</button></div>`:`<strong>${esc(menuItem.name)}</strong><button class="secondary btn-wide" data-action="rename-resume">重命名</button><button class="secondary btn-wide" data-action="set-default-resume" data-index="${state.resumeMenuIndex}" ${state.resumeMenuIndex===state.defaultResume?'disabled':''}>设为默认简历</button><button class="danger btn-wide" data-action="delete-resume" data-index="${state.resumeMenuIndex}">删除这份简历</button><p class="snapshot-footnote">删除不会改变已有面试计划和历史报告中的文本快照。</p>`}</div></div>`:''}`}

function alignedRounds(){const plan=currentPlan();return `<div class="rounds-page">${topbar('项目深挖面试','home')}<div class="round-summary"><span>经历　<b>${esc(plan.experience.title)}</b></span><span>面试官　<b>${state.interviewers.length} 位</b></span></div>${state.interviewers.map((p,i)=>{const status=interviewerStatus(i),sessions=interviewerSessions(i),active=sessions.find(x=>x.status==='in_progress');return `<section class="interviewer session-interviewer"><span class="face ${i===0?'green':i===2?'yellow':''}">•ᴗ•</span><span><h3>${esc(p.name)} · ${esc(p.role)}</h3><p>${esc(p.style)} · ${esc(p.focus)}</p><em class="session-state ${status==='已完成'?'done':status==='进行中'?'active':''}">${status}${status==='已完成'?` · ${sessions.length} 场`:status==='进行中'?` · 第 ${Math.min((active?.currentTurn||0)+1,4)}/4 问`:' · 尚无场次'}</em></span><button class="secondary" data-action="open-sessions" data-index="${i}">场次 ›</button></section>`}).join('')}<div class="ms1-note">每场面试只有一位面试官。岗位与经历快照共享，进度、问答、报告和复练历史相互独立。</div>`}

function alignedSessions(){const p=state.interviewers[state.activeInterviewer]||state.interviewers[0],sessions=interviewerSessions(state.activeInterviewer);return `${topbar('面试场次','rounds')}<div class="snapshot-card"><b>${esc(p.role)}</b><p>${esc(p.style)}</p><p>${esc(p.focus)}</p></div>${sessions.map((session,i)=>`<section class="session-card"><span class="session-index">${String(sessions.length-i).padStart(2,'0')}</span><span><small>${session.time} · ${session.duration}</small><strong>项目深挖</strong><em>${session.status==='completed'?'4 个有效回答 · 4 条反馈':`已完成 ${session.currentTurn||0} 个有效回答 · 当前第 ${Math.min((session.currentTurn||0)+1,4)} 问`}</em></span><span class="session-status ${session.status==='in_progress'?'active':''}">${session.status==='completed'?'已完成':'进行中'}</span><button class="${session.status==='completed'?'secondary':'primary'}" data-action="${session.status==='completed'?'open-complete-report':'continue-current'}" data-session-id="${session.id}">${session.status==='completed'?'报告':'继续'}</button></section>`).join('')}${!sessions.length?'<div class="empty-state"><b>还没有面试场次</b><p>开始后，这位面试官的进度、报告和复练版本会独立保存。</p></div>':''}<button class="primary btn-wide" data-action="new-session">${sessions.some(x=>x.status==='completed')?'再练一场':'开始新场次'}</button>`}

const characterAvatar=(index,large=false)=>`<span class="face character-avatar character-${index%6} ${large?'large':''}" aria-hidden="true"><i class="character-hair"></i><i class="character-eyes"></i><i class="character-mouth"></i><i class="character-detail"></i></span>`;
function alignedPractice(){const p=state.interviewers[state.activeInterviewer]||state.interviewers[0],turn=Math.min(state.interviewTurn,3),phase=state.interviewPhase,question=currentQuestions()[turn],heard=state.questionInterrupted?`${question.split(/\s+/).slice(0,10).join(' ')}…`:question,answer=state.turnTranscripts[turn]||(phase==='user'?state.currentTranscript:'');const phaseCopy={connecting:['连接中','正在建立受保护的语音连接'],ai:['面试官提问中','持续监听已开启，你开口后面试官会自动停止播放'],user:['用户回答中','请用英文回答，面试官不会在你持续说话时抢话'],processing:['正在处理回答','正在保存原音并检查转录是否可用'],reconnect:['连接已中断','当前问题已保留，未完成音频已丢弃']}[phase]||['面试官提问中','请开始回答'];return `<div class="practice"><div class="practice-head"><button class="ghost-icon" data-route="sessions">‹</button><h1>项目深挖</h1><span class="chip">${turn+1} / 4</span></div><div class="turn-progress">${currentQuestions().map((_,i)=>`<i class="${i<=turn?'active':''}"></i>`).join('')}</div>${state.interviewChatOpen?`<section class="interview-chat-view"><header class="interview-chat-head"><span><small>${esc(p?.name||'Interviewer')} · ${esc(p?.role||'Interviewer')}</small><h2>本题对话</h2></span><button class="ghost-icon" data-action="close-interview-chat" aria-label="关闭对话">×</button></header><article class="chat-bubble interviewer-bubble"><small>${esc(p?.name||'Interviewer')}</small><p>${heard}</p><button class="bubble-replay" data-action="replay-question"><span aria-hidden="true">↻</span>重新播放问题</button></article><article class="chat-bubble candidate-bubble"><small>你</small><p>${answer?esc(answer):'尚未提交回答。'}</p></article><button class="secondary btn-wide" data-action="close-interview-chat">返回面试</button></section>`:`<div class="voice-state">${characterAvatar(state.activeInterviewer,true)}<h2>${phaseCopy[0]}</h2><p>${phaseCopy[1]}</p></div><div class="question-card"><small class="question-label">${['项目概览','个人贡献','方案取舍','验证与结果'][turn]}</small>${heard}${state.questionInterrupted?'<small class="interrupted-label">已中断 · 只展示实际播放片段</small>':phase==='ai'?'<small>正在播放 · 开口即可打断</small>':''}</div>${state.questionError?`<div class="form-error">${state.questionError}</div><button class="primary btn-wide" data-action="retry-question">重新生成并播放本题</button>`:''}${phase==='user'?`<label class="field-label">可用转录（原型中可编辑以验证过短回答）</label><textarea class="field" data-answer-transcript>${esc(state.currentTranscript)}</textarea>${state.answerError?`<div class="form-error">${state.answerError}</div>`:''}`:''}${phase==='reconnect'?'<button class="primary btn-wide" data-action="reconnect-current">重新连接并重答本题</button>':`<div class="practice-controls unified-session-controls"><button class="round-btn" data-action="toggle-interview-chat" aria-label="查看本题对话"><span>💬</span><small>对话</small></button><button class="talk ${phase==='user'?'recording':''}" data-action="ms1-answer" ${phase==='connecting'||phase==='processing'||state.questionError?'disabled':''}>${phase==='user'?'提交回答':'开口回答'}</button><button class="round-btn" data-action="end-early" aria-label="结束"><span>⏹</span><small>结束</small></button></div>`}`}</div>`}

const syncReportScrollState=scroller=>{
  if(!scroller)return;
  const card=scroller.closest('.report-question-card'),max=Math.max(0,scroller.scrollHeight-scroller.clientHeight),scrollable=max>3;
  card?.classList.toggle('is-scrollable',scrollable);
  card?.classList.toggle('at-end',!scrollable||scroller.scrollTop>=max-3);
};
const reportCard=(i,allowRetry=true)=>{
  const f=ms1Feedback[i],attempts=state.retryAttempts[i]||[],transcript=state.turnTranscripts[i]||transcriptsForRound()[i],result=retryMocksForRound()[i],question=activeSession()?.heardQuestions?.[i]||currentQuestions()[i];
  const isRole=activeSession()?.practiceKey==='role-chat',labels=isRole?['开场','本地特色','旅行建议','深入交流']:roundLabels();
  const languageIssue=isRole?roleLanguageIssue:currentReportLanguageIssues()[i],languageSaved=languageIssue&&isMistakeSaved(languageIssue.id);
  return `<article class="evidence-card report-question-card" data-report-index="${i}" aria-label="第 ${i+1} 问反馈">
    <div class="report-question-scroll" data-report-scroll>
      <header><span><small>第 ${i+1} 问 · ${labels[i]}</small><h3>${question}</h3></span><em class="evidence-status ${f.status==='证据完整'?'complete':''}">${f.status}</em></header>
      <button class="audio-protected" data-action="protected-audio">▶ <span><b>回听原回答</b></span></button>
      <p><b>完整转录</b><br>${esc(transcript)}</p>
      <blockquote>${f.quote}</blockquote>
      <p><b>诊断</b><br>${f.diagnosis}</p>
      <div class="retry-goal"><b>下一次改进目标</b><br>${f.target}</div>
      ${languageIssue?`<section class="report-language-issue ${languageSaved?'saved':''}" data-language-issue="${languageIssue.id}"><header><span><small>语言问题 · ${esc(languageIssue.type)}</small><b>${esc(languageIssue.title)}</b></span><button data-action="toggle-report-mistake" data-mistake-id="${languageIssue.id}" aria-pressed="${languageSaved}">${languageSaved?'已加入':'加入错题'}</button></header><p><del>${esc(languageIssue.original)}</del><span aria-hidden="true">→</span><strong>${esc(languageIssue.recommended)}</strong></p><small>${esc(languageIssue.explanation)}</small></section>`:''}
      ${attempts.length?`<div class="latest-retry"><small>最近复练</small><b>${attempts.at(-1).time}</b><span>${result.added.replace('\n',' · ')}；${result.missing}</span></div>`:''}
      ${allowRetry?`<button class="primary btn-wide" data-action="open-retry" data-index="${i}">同题复练</button><button class="version-row" data-action="toggle-versions" data-index="${i}"><span><b>全部回答版本</b><small>原回答 + ${attempts.length} 次复练，音频与转录分别保存</small></span><b>›</b></button>`:'<div class="ms1-note">未完成场次不开放同题复练。</div>'}
    </div>
    <div class="report-scroll-cue" aria-hidden="true"><span>↓</span> 继续下滑</div>
  </article>`;
};
const reportDate=()=>new Intl.DateTimeFormat('zh-CN',{year:'numeric',month:'2-digit',day:'2-digit'}).format(new Date()).replaceAll('/','.');
function alignedReport(){
  const backRoute='home';
  if(state.reportStatus==='generating')return `<div class="align-page report-page report-page-static">${topbar('生成面试报告',backRoute)}<div class="report-loading"><i></i><i></i><i></i><h2>正在生成证据反馈</h2><p>已完成的有效回答、原音和转录已经安全保存。</p></div></div>`;
  if(state.reportStatus==='failed')return `<div class="align-page report-page report-page-static">${topbar('生成面试报告',backRoute)}<div class="empty-state"><b>报告生成失败</b><p>面试记录已经保存，不需要重新完成面试。</p><button class="primary btn-wide" data-action="retry-report">单独重试生成报告</button></div></div>`;

  const completed=state.sessionComplete?ms1Feedback.length:Math.min(state.interviewTurn,ms1Feedback.length);
  const summary=state.sessionComplete?(isHrRound()?'求职动机、岗位匹配和协作表达清楚；下次补充离职原因与职业规划的具体依据。':'架构和可靠性结果表达清楚；下次补充事务边界与技术取舍依据。'):'已保存完成的有效回答，未完成部分不生成反馈。';
  state.reportCarouselIndex=Math.max(0,Math.min(Number(state.reportCarouselIndex)||0,Math.max(0,completed-1)));
  const cards=Array.from({length:completed},(_,i)=>reportCard(i,state.sessionComplete)).join('');
  const dots=Array.from({length:completed},(_,i)=>`<button class="${i===state.reportCarouselIndex?'active':''}" data-action="align-report-carousel-to" data-index="${i}" aria-label="查看第 ${i+1} 问"></button>`).join('');
  requestAnimationFrame(()=>{const track=document.querySelector('[data-report-carousel]'),card=track?.querySelector(`[data-report-index="${state.reportCarouselIndex}"]`);document.querySelectorAll('[data-report-scroll]').forEach(syncReportScrollState);if(track&&card&&state.route==='report')track.scrollLeft=card.offsetLeft-track.offsetLeft});
  return `<div class="align-page report-page">
    ${topbar(state.sessionComplete?'面试报告总结':'未完成报告',backRoute)}
    <section class="report-overview" aria-label="报告概要"><div><small>${reportDate()}</small><b>${activeSession()?.duration||'12 分钟'} · ${completed} / 4</b></div><p>${summary}</p></section>
    ${completed?`<div class="report-question-track" data-report-carousel>${cards}</div><nav class="report-question-dots" aria-label="报告问题">${dots}</nav>`:'<div class="report-empty">本场没有有效回答，因此没有生成问题反馈。</div>'}
  </div>`;
}

function alignedRetry(){
  const i=state.reportExpanded??0,f=ms1Feedback[i],attempts=state.retryAttempts[i]||[],mock=retryMocksForRound()[i],question=currentQuestions()[i],attemptNumber=attempts.length+1;
  return `<div class="align-page retry-page">
    ${topbar('同题复练','report')}
    <main class="retry-page-content">
      <div class="retry-page-meta">第 ${attemptNumber} 次复练</div>
      <section class="retry-question-panel"><small>原问题</small><h1>${question}</h1></section>
      <section class="retry-target-panel"><small>本次改进目标</small><p>${f.target}</p></section>
      ${state.retryRecording?`<section class="retry-transcript-panel"><small>新回答转录</small><p>${mock.transcript}</p></section>`:''}
      ${state.showVersions?`<section class="retry-feedback"><div><small>已补充</small><b>${mock.added.replace('\n','<br>')}</b></div><div><small>仍缺少</small><b>${mock.missing}</b></div></section><h2 class="retry-version-title">回答版本</h2><button class="audio-protected retry-audio" data-action="protected-audio">▶ <span><b>原回答</b><small>01:40 · ${esc(state.turnTranscripts[i]||transcriptsForRound()[i])}</small></span></button>${attempts.map((a,n)=>`<button class="audio-protected retry-audio" data-action="protected-audio">▶ <span><b>复练 ${n+1} · ${a.time}</b><small>${a.audio} · ${a.transcript}</small></span></button>`).join('')}`:''}
    </main>
    <footer class="retry-page-actions"><button class="retry-page-primary ${state.retryRecording?'recording':''}" data-action="retry-record">${state.retryRecording?'提交回答':state.showVersions?'再次复练':'开始回答'}</button><small>每次复练保存为新版本，不覆盖原回答。</small></footer>
  </div>`;
}

function alignedInterviewersV2(){const canSave=state.interviewers.length>=1&&state.interviewers.length<=4;return `${topbar('确认面试官','create-plan','<span class="chip">1-4 位</span>')}${steps(3)}<p style="color:var(--muted)">请确认本计划的面试官。每位面试官对应独立场次，可编辑姓名、职责、风格和关注点。</p>${state.interviewers.map((p,i)=>{const editing=state.editingInterviewerIndex===i;return `<div class="interviewer ms1-interviewer ${editing?'editing':''}"><span class="face ${i===0?'green':i===2?'yellow':''}">•ᴗ•</span><span class="ms1-edit">${editing?`<label>姓名<input data-person="name" data-index="${i}" value="${esc(p.name)}" aria-label="姓名"></label><label>职责<input data-person="role" data-index="${i}" value="${esc(p.role)}" aria-label="职责"></label><label>面试风格<input data-person="style" data-index="${i}" value="${esc(p.style)}" aria-label="面试风格"></label><label>关注点<input data-person="focus" data-index="${i}" value="${esc(p.focus)}" aria-label="关注点"></label>`:`<span class="interviewer-read"><strong>${esc(p.name)}</strong><b>${esc(p.role)}</b><span>${esc(p.style)}</span><span>${esc(p.focus)}</span></span>`}</span><span class="interviewer-card-actions">${editing?`<button class="interviewer-save" data-action="save-interviewer" data-index="${i}">保存</button>`:`<button class="interviewer-edit" data-action="edit-interviewer" data-index="${i}">编辑</button>`}<button class="remove" data-action="remove-interviewer" data-index="${i}" aria-label="删除面试官">×</button></span></div>`}).join('')}<button class="secondary btn-wide" data-action="add-interviewer" ${state.interviewers.length>=4?'disabled':''}>＋ 添加面试官</button>${!canSave?'<div class="form-error">面试官数量必须为 1-4 位。</div>':''}<div class="sticky-actions"><button class="secondary" data-route="create-plan">返回</button><button class="primary" data-action="save-plan" ${canSave?'':'disabled'}>保存面试计划</button></div>`}

function renderManualSections(item){
  const md=item.manualData;if(!md)return"";
  const exp=state.manualSection,edSec=state.manualEditSection,edIdx=state.manualEditIdx,d=state.manualDraft||{};
  const head=(key,label,icon,count)=>`<div class="manual-section ${exp===key?"expanded":""}"><div class="manual-section-head" data-action="toggle-manual" data-section="${key}"><span class="manual-section-icon">${icon}</span><div class="manual-section-title"><b>${label}</b>${count?`<small>${count}</small>`:""}</div><svg class="manual-chevron" viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><polyline points="6 9 12 15 18 9"/></svg></div>`;
  const end=()=>`</div>`;
  const f=(sec,field,label,val,ph,ml,idx)=>`<div class="exp-field"><label>${label}</label>${ml?`<textarea data-manual-field="${field}" data-section="${sec}" data-index="${idx}" placeholder="${ph}">${esc(val)}</textarea>`:`<input data-manual-field="${field}" data-section="${sec}" data-index="${idx}" value="${esc(val)}" placeholder="${ph}">`}</div>`;
  const multiSec=(key,label,icon,entries,fields)=>{let h=head(key,label,icon,entries.length?`${entries.length} 条`:"");if(exp===key){h+=`<div class="manual-section-body">`;entries.forEach((entry,i)=>{const isEd=edSec===key&&edIdx===i;const dd=isEd?d:entry;h+=`<div class="manual-entry ${isEd?"editing":""}">`;if(!isEd){fields.forEach(fld=>{h+=`<div class="exp-field"><label>${fld.label}</label><p class="field-text">${esc(entry[fld.key]||"未填写")}</p></div>`});h+=`<div class="exp-card-actions"><button data-action="edit-manual" data-section="${key}" data-index="${i}">编辑</button><button class="danger" data-action="delete-manual" data-section="${key}" data-index="${i}">删除</button></div>`}else{fields.forEach(fld=>{h+=f(key,fld.key,fld.label,dd[fld.key]||"",fld.ph,fld.multi,i)});h+=`<div class="exp-card-actions"><button class="danger" data-action="delete-manual" data-section="${key}" data-index="${i}">删除</button><button data-action="cancel-manual">取消</button><button class="primary" data-action="save-manual" data-section="${key}" data-index="${i}">保存</button></div>`}h+=`</div>`});h+=`<button class="exp-add" data-action="add-manual" data-section="${key}"><svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>添加</button></div>`}return h+end()};
  const userIcon=`<svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>`;
  const briefIcon=`<svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><rect x="2" y="7" width="20" height="14" rx="2"/><path d="M16 21V5a2 2 0 0 0-2-2h-4a2 2 0 0 0-2 2v16"/></svg>`;
  const folderIcon=`<svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z"/></svg>`;
  const awardIcon=`<svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="8" r="6"/><path d="M15.477 12.89 17 22l-5-3-5 3 1.523-9.11"/></svg>`;
  const starIcon=`<svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"/></svg>`;
  const workFields=[{key:"company",label:"公司名称",ph:"e.g., ByteDance",multi:false},{key:"role",label:"职位",ph:"e.g., Backend Development Intern",multi:false},{key:"date",label:"时间",ph:"e.g., 2025.03 - 2025.09",multi:false},{key:"description",label:"工作内容",ph:"Describe your main responsibilities and achievements",multi:true}];
  const projFields=[{key:"title",label:"项目名称",ph:"e.g., High-Concurrency E-Commerce System",multi:false},{key:"type",label:"经历类型",ph:"e.g., Backend Project",multi:false},{key:"date",label:"时间",ph:"e.g., 2025.01 - Present",multi:false},{key:"stack",label:"技术栈",ph:"e.g., Java · Spring Boot · Redis",multi:false},{key:"background",label:"项目背景",ph:"Describe the business context and goals",multi:true},{key:"role",label:"个人职责",ph:"Describe your core responsibilities",multi:true},{key:"result",label:"项目成果",ph:"Describe quantifiable results and impact",multi:true}];
  const honorFields=[{key:"title",label:"奖项名称",ph:"e.g., ACM-ICPC Silver Medal",multi:false},{key:"date",label:"时间",ph:"e.g., 2024.11",multi:false},{key:"description",label:"描述",ph:"Briefly describe the award",multi:true}];
  const skillFields=[{key:"category",label:"技能分类",ph:"e.g., Programming Languages",multi:false},{key:"items",label:"技能详情",ph:"e.g., Java, Go, Python, JavaScript",multi:true}];
  let html="";
  html+=head("background","个人背景",userIcon,"");
  if(exp==="background"){html+=`<div class="manual-section-body">`;
    html+=f("background","name","姓名",md.background.name,"Enter your name",false,0);
    html+=f("background","title","求职意向",md.background.title,"e.g., Backend Development Engineer",false,0);
    html+=f("background","phone","电话",md.background.phone,"Enter your phone number",false,0);
    html+=f("background","email","邮箱",md.background.email,"Enter your email address",false,0);
    html+=f("background","education","教育背景",md.background.education,"e.g., XYZ University, Computer Science, B.S.",false,0);
    html+=f("background","summary","个人简介",md.background.summary,"Briefly introduce your background and career direction",true,0);
    html+=`<div class="exp-card-actions"><button class="primary" data-action="save-manual" data-section="background" data-index="0">保存</button></div></div>`}
  html+=end();
  html+=multiSec("work","工作/实习经历",briefIcon,md.work,workFields);
  html+=multiSec("projects","项目经历",folderIcon,md.projects,projFields);
  html+=multiSec("honors","荣誉奖项",awardIcon,md.honors,honorFields);
  html+=multiSec("skills","个人技能",starIcon,md.skills,skillFields);
  return html;
}
function alignedResumesV2(){const atLimit=state.resumeItems.length>=3,menuItem=state.resumeItems[state.resumeMenuIndex],failed=item=>['解析失败','内容为空'].includes(item.status),activeItem=state.resumeItems[state.selectedResumeIndex]||state.resumeItems[state.defaultResume]||state.resumeItems[0],exps=activeItem?.experienceData||[],hasContent=(exps.length>0&&activeItem?.status==='可用')||!!activeItem?.manualData;const expCard=(exp,i)=>{const expanded=state.expExpanded===i,editing=state.expEditIndex===i,d=state.expDraft&&state.expEditIndex===i?state.expDraft:exp;return `<div class="exp-card ${expanded?'expanded':''}"><div class="exp-card-head" data-action="toggle-exp" data-index="${i}"><span class="exp-card-num">${i+1}</span><div class="exp-card-title"><b>${esc(exp.title||'未命名经历')}</b><small>${exp.type||''}${exp.date?' · '+exp.date:''}</small></div><button class="exp-card-toggle" tabindex="-1"><svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><polyline points="6 9 12 15 18 9"/></svg></button></div>${expanded?`<div class="exp-card-body">${editing?`<div class="exp-field"><label>项目名称</label><input data-exp-inline="title" data-index="${i}" value="${esc(d.title)}" placeholder="e.g., High-Concurrency E-Commerce System"></div><div class="exp-field"><label>经历类型</label><input data-exp-inline="type" data-index="${i}" value="${esc(d.type)}" placeholder="e.g., Backend Project"></div><div class="exp-field"><label>时间</label><input data-exp-inline="date" data-index="${i}" value="${esc(d.date)}" placeholder="e.g., 2025.01 - Present"></div><div class="exp-field"><label>技术栈</label><input data-exp-inline="stack" data-index="${i}" value="${esc(d.stack)}" placeholder="e.g., Java · Spring Boot · Redis"></div><div class="exp-field"><label>项目背景</label><textarea data-exp-inline="background" data-index="${i}" placeholder="Describe the business context and goals">${esc(d.background)}</textarea></div><div class="exp-field"><label>个人职责</label><textarea data-exp-inline="role" data-index="${i}" placeholder="Describe your core responsibilities">${esc(d.role)}</textarea></div><div class="exp-field"><label>项目成果</label><textarea data-exp-inline="result" data-index="${i}" placeholder="Describe quantifiable results and impact">${esc(d.result)}</textarea></div><div class="exp-card-actions"><button class="danger" data-action="delete-exp-inline" data-index="${i}">删除</button><button data-action="cancel-exp-inline" data-index="${i}">取消</button><button class="primary" data-action="save-exp-inline" data-index="${i}">保存</button></div>`:`<div class="exp-field"><label>技术栈</label><div class="tech-tags">${(d.stack||'').split('·').map(s=>s.trim()).filter(Boolean).map(s=>`<code>${esc(s)}</code>`).join('')||'<code style=background:transparent;color:#C8C4D5>未填写</code>'}</div></div><div class="exp-field"><label>项目背景</label><p class="field-text">${esc(d.background||'未填写')}</p></div><div class="exp-field"><label>个人职责</label><p class="field-text">${esc(d.role||'未填写')}</p></div><div class="exp-field"><label>项目成果</label><p class="field-text">${esc(d.result||'未填写')}</p></div><div class="exp-card-actions"><button data-action="edit-exp-inline" data-index="${i}">编辑经历</button></div>`}</div>`:''}</div>`};return `${topbar('个人简历',state.resumeReturnRoute||'profile',`<span class="chip">${state.resumeItems.length} / 3</span>`)}<div class="resumes-page"><p class="page-intro">上传 PDF 简历或手动编写经历，AI 会提取项目与工作经历，用于生成更贴合的面试问题。</p><div class="resume-methods"><button class="resume-method" data-action="upload-resume" ${atLimit?'disabled':''}><span class="method-icon"><svg viewBox="0 0 24 24" width="22" height="22" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg></span><strong>上传简历</strong><small>PDF 格式，最大 10 MB</small></button><button class="resume-method" data-action="write-resume" ${atLimit?'disabled':''}><span class="method-icon"><svg viewBox="0 0 24 24" width="22" height="22" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg></span><strong>编写简历</strong><small>手动填写项目经历</small></button></div><div class="resume-list">${state.resumeItems.map((item,i)=>`<section class="resume-card ${i===state.defaultResume?'active':''} ${failed(item)?'failed':''}"><div class="resume-main"><div class="resume-icon"><svg viewBox="0 0 24 24" width="22" height="22" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8Z"/><path d="M14 2v6h6"/><path d="M16 13H8"/><path d="M16 17H8"/><path d="M10 9H8"/></svg></div><div class="resume-info"><h3>${esc(item.name)}</h3><p>${item.size}${item.experiences?` · ${item.experiences} 条经历`:''}</p><div class="resume-badges"><span class="resume-state ${failed(item)||item.status==='上传失败'?'fail':''}">${i===state.defaultResume?'默认 · ':''}${item.status}</span>${state.resumeReturnRoute==='create-plan'&&item.status==='可用'?`<button class="resume-use-chip" data-action="use-resume" data-index="${i}" ${i===state.selectedResumeIndex?'disabled':''}>${i===state.selectedResumeIndex?'已选择':'使用'}</button>`:''}${failed(item)?`<button class="resume-use-chip secondary" data-action="manual-experience" data-index="${i}">手动填写</button>`:''}</div></div><button class="resume-menu-btn" data-action="resume-menu" data-index="${i}" aria-label="简历操作"><svg viewBox="0 0 24 24" width="18" height="18" fill="currentColor" aria-hidden="true"><circle cx="12" cy="6" r="2"/><circle cx="12" cy="12" r="2"/><circle cx="12" cy="18" r="2"/></svg></button></div></section>`).join('')}</div>${!state.resumeItems.length?'<div class="empty-state"><b>还没有简历</b><p>上传 PDF 简历或手动编写，系统会提取项目与实习经历。</p></div>':''}${hasContent?(activeItem.manualData?renderManualSections(activeItem):`<div class="exp-section"><div class="exp-section-head"><h3>解析出的经历</h3><span class="exp-count">${exps.length} 条 · 可编辑</span></div><div class="exp-list">${exps.map((exp,i)=>expCard(exp,i)).join('')}</div><button class="exp-add" data-action="add-exp-inline"><svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>添加一条经历</button><p class="exp-source-note">经历修改会实时同步到简历，生成面试计划时使用最新内容。</p></div>`):''}${state.resumeError?`<div class="form-error">${state.resumeError}</div><button class="secondary btn-wide" data-action="clear-resume-error">重新选择文件</button>`:''}${state.resumeItems.some(failed)?'<div class="form-error resume-global-error">未识别到有效经历。可在对应简历卡片中手动填写，或重试解析。</div><button class="secondary btn-wide" data-action="retry-resume">重试解析</button>':''}</div>${menuItem?`<div class="sheet"><div class="sheet-card"><div class="topbar"><h2>简历操作</h2><button class="ghost-icon" data-action="close-resume-menu">×</button></div>${state.resumeRenaming?`<div class="exp-field"><label>简历名称</label><input data-resume-rename value="${esc(menuItem.name)}" placeholder="请输入简历名称"></div><div class="exp-card-actions"><button data-action="cancel-rename-resume">取消</button><button class="primary" data-action="save-rename-resume" data-index="${state.resumeMenuIndex}">保存</button></div>`:`<strong>${esc(menuItem.name)}</strong><button class="secondary btn-wide" data-action="rename-resume">重命名</button><button class="secondary btn-wide" data-action="set-default-resume" data-index="${state.resumeMenuIndex}" ${state.resumeMenuIndex===state.defaultResume?'disabled':''}>设为默认简历</button><button class="danger btn-wide" data-action="delete-resume" data-index="${state.resumeMenuIndex}">删除这份简历</button><p class="snapshot-footnote">删除不会改变已有面试计划和历史报告中的文本快照。</p>`}</div></div>`:''}`}

function alignedRoundsV2(){const plan=currentPlan();return `<div class="rounds-page">${topbar('项目深挖面试','home')}<div class="round-summary"><span>简历　<b>${esc(plan.resumeName||'Backend_Developer_Resume.pdf')}</b></span><span>面试官　<b>${state.interviewers.length} 位</b></span></div>${state.interviewers.map((p,i)=>{const status=interviewerStatus(i),sessions=interviewerSessions(i),active=sessions.find(x=>x.status==='in_progress'),incomplete=sessions.filter(x=>x.status==='incomplete').length,detail=status==='已完成'?` · ${sessions.length} 场`:status==='进行中'?` · 第 ${Math.min((active?.currentTurn||0)+1,4)}/4 问`:status==='未完成'?` · ${incomplete} 场未完成`:' · 尚无场次';return `<section class="interviewer session-interviewer"><span class="face ${i===0?'green':i===2?'yellow':''}">•ᴗ•</span><span><h3>${esc(p.name)} · ${esc(p.role)}</h3><p>${esc(p.style)} · ${esc(p.focus)}</p><em class="session-state ${status==='已完成'?'done':status==='进行中'?'active':''}">${status}${detail}</em></span><button class="secondary" data-action="open-sessions" data-index="${i}">场次 ›</button></section>`}).join('')}<div class="ms1-note">每场面试只有一位面试官。四位面试官共享岗位与整份简历快照，但进度、问答、报告和复练历史相互独立。</div>`}

function alignedHome(){const allSessions=state.plans.flatMap(plan=>plan.sessions.flat()),completed=allSessions.filter(x=>x.status==='completed').length,retries=allSessions.reduce((sum,session)=>sum+Object.values(session.retryAttempts||{}).flat().length,0);return `<div class="history-page"><header class="history-head"><div><small>INTERVIEW HISTORY</small><h1>面试历史</h1><p>按计划查看每位面试官的独立场次、报告与复练版本。</p></div><span class="history-count">${state.plans.length} 个计划</span></header>${state.plans.length?`<section class="history-overview"><div><small>面试计划</small><b>${state.plans.length} 个</b></div><div><small>已完成场次</small><b>${completed} 场</b></div><div><small>复练版本</small><b>${retries} 个</b></div></section><section class="history-list">${state.plans.map(plan=>{const entries=plan.sessions.flatMap((list,interviewerIndex)=>list.map(session=>({session,interviewerIndex}))).sort((a,b)=>(b.session.ts||0)-(a.session.ts||0)),recent=entries[0],name=recent?plan.interviewers[recent.interviewerIndex]?.name:'',progress=recent?.session.currentTurn||0;return `<button class="history-card interview" data-action="open-plan" data-plan-id="${plan.id}"><span class="history-art interview-icon"><svg viewBox="0 0 24 24" width="24" height="24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M12 2a3 3 0 0 1 3 3v6a3 3 0 0 1-6 0V5a3 3 0 0 1 3-3Z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="22"/><line x1="8" y1="22" x2="16" y2="22"/></svg></span><span class="history-copy"><small>面试计划 · 项目深挖</small><strong>${esc(plan.snapshot.jobName)}</strong><em><span class="recent-person">${esc(name)}</span><span>${recent?.session.time||'尚未开始'}，${recent?.session.status==='completed'?'已完成':recent?.session.status==='incomplete'?'未完成':`第 ${Math.min(progress+1,4)} 问进行中`}</span></em><span class="history-progress"><i style="width:${Math.min((progress/4)*100,100)}%"></i></span></span><span class="history-open">查看</span></button>`}).join('')}</section><div class="ms1-note">每个计划使用创建时确认的岗位与经历快照。以后修改或删除简历，不会改变历史报告。</div>`:'<div class="empty-state"><b>还没有面试计划</b><p>填写目标岗位并确认一条经历后，即可开始项目深挖面试。</p><button class="primary btn-wide" data-route="create-job">创建面试计划</button></div>'}</div>`}
function alignedSessionsV2(){const p=state.interviewers[state.activeInterviewer]||state.interviewers[0],sessions=interviewerSessions(state.activeInterviewer),inProgress=sessions.find(x=>x.status==='in_progress');return `${topbar('面试场次','rounds')}<div class="snapshot-card"><b>${esc(p.role)}</b><p>${esc(p.style)}</p><p>${esc(p.focus)}</p></div>${sessions.map((session,i)=>{const completed=session.status==='completed',incomplete=session.status==='incomplete',label=completed?'已完成':incomplete?'未完成':'进行中',action=completed?'open-complete-report':incomplete?'open-incomplete-report':'continue-current';return `<section class="session-card"><span class="session-index">${String(sessions.length-i).padStart(2,'0')}</span><span><small>${session.time} · ${session.duration}</small><strong>项目深挖</strong><em>${completed?'4 个有效回答 · 4 条反馈':incomplete?`完成 ${session.currentTurn||0} 个有效回答 · 未完成报告`:`已完成 ${session.currentTurn||0} 个有效回答 · 当前第 ${Math.min((session.currentTurn||0)+1,4)} 问`}</em></span><span class="session-status ${session.status==='in_progress'?'active':''}">${label}</span><button class="${session.status==='in_progress'?'primary':'secondary'}" data-action="${action}" data-session-id="${session.id}">${completed?'报告':incomplete?'未完成报告':'继续'}</button></section>`}).join('')}${!sessions.length?'<div class="empty-state"><b>还没有面试场次</b><p>开始后，这位面试官的进度、报告和复练版本会独立保存。</p></div>':''}<button class="primary btn-wide" data-action="${inProgress?'continue-current':'new-session'}" ${inProgress?`data-session-id="${inProgress.id}"`:''}>${inProgress?'继续当前面试':sessions.length?'再练一场':'开始新场次'}</button>`}
function interviewLiveSession(){const p=state.interviewers[state.activeInterviewer]||state.interviewers[0],turn=Math.min(state.interviewTurn,3),question=currentQuestions()[turn];return `<section class="live-session interview-live-session"><div class="live-status"><span></span>实时面试已连接</div><div class="live-person"><div class="live-orb"><i></i><i></i>${characterAvatar(state.activeInterviewer,true)}</div><h2>正在和 ${esc(p.name)} 实时面试</h2><p>直接开口回答。系统会判断你的停顿，并自动进入下一轮追问。</p></div><div class="live-question"><small>当前问题</small><b>${esc(question)}</b></div><div class="live-wave" aria-hidden="true"><i></i><i></i><i></i><i></i><i></i><i></i><i></i></div><div class="live-listening-row"><small>正在聆听</small><button data-action="interrupt-live">打断提问</button></div><button class="end-live" data-action="toggle-live">退出实时模式</button></section>`}
function unifiedInterviewPractice(){if(state.liveMode){const turn=Math.min(state.interviewTurn,3);return `<div class="practice"><div class="practice-head"><button class="ghost-icon" data-route="sessions">‹</button><h1>项目深挖</h1><span class="chip">${turn+1} / 4</span></div><div class="turn-progress">${currentQuestions().map((_,i)=>`<i class="${i<=turn?'active':''}"></i>`).join('')}</div>${liveModeControl()}${interviewLiveSession()}</div>`}return alignedPractice().replace(/(<div class="turn-progress">.*?<\/div>)/,`$1${liveModeControl()}`)}
const withCharacterAvatars=html=>{let index=0;return html.replace(/<span class="face[^\"]*">•ᴗ•<\/span>/g,()=>characterAvatar(index++))};
const addSampleAnswerFeedback=html=>html.replace('<p>尚未提交回答。</p></article>',`<p class="sample-answer">We <span class="answer-mistake">test</span> the system by <span class="answer-mistake">send</span> two thousand requests per second, and it <span class="answer-mistake">didn't failed</span> when Kafka was down.</p><aside class="answer-corrections"><b>发现 3 处表达问题</b><div class="answer-fix-list"><span class="answer-fix"><del>test</del><i>→</i><strong>tested</strong><em>描述已经完成的验证，应使用过去时。</em></span><span class="answer-fix"><del>send</del><i>→</i><strong>sending</strong><em>介词 by 后使用动名词。</em></span><span class="answer-fix"><del>didn't failed</del><i>→</i><strong>didn't fail</strong><em>助动词 did 后使用动词原形。</em></span></div></aside></article>`);
