const addRetryContext=html=>html;
const views={'auth':alignedAuth,'home':()=>{if(state.historyChatOpen&&window.historyConversationView)return historyConversationView();return addMistakeEntry(alignedHome())},'create-hub':ms1CreateHub,'create-job':createJob,'create-plan':alignedCreatePlan,'interviewers':()=>withCharacterAvatars(alignedInterviewersV2()),'rounds':()=>withCharacterAvatars(alignedRoundsV2()),'sessions':alignedSessionsV2,'mic-check':ms1Mic,'practice':()=>addSampleAnswerFeedback(unifiedInterviewPractice()),'report':()=>addMistakeReportEntry(alignedReport()),'retry':()=>addRetryContext(alignedRetry()),'mistakes':mistakes,'mistake-practice':mistakePractice,'mistake-complete':mistakeComplete,'role-create':roleCreate,'role-generating':roleGenerating,'role-preview':rolePreview,'role-chat':roleChat,'profile':ms1Profile,'resumes':alignedResumesV2,'settings':ms1Settings};
