const technicalize=html=>{const aligned=technicalCopyMap.reduce((out,[from,to])=>out.split(from).join(to),html),complete=ms1Feedback.filter(item=>item.status==='证据完整').length;return aligned.replace('4 个固定目标均已覆盖，其中 2 条证据完整，2 条需要补充。',`4 个固定目标均已覆盖，其中 ${complete} 条证据完整，${4-complete} 条需要补充。`)};
function render(){if(['report','retry'].includes(state.route))syncFeedbackFromTranscripts();const isTab=['agent-chat','home','profile'].includes(state.route);S.classList.toggle('has-bottom-tabs',isTab);S.classList.toggle('report-canvas',state.route==='report');S.classList.toggle('retry-canvas',state.route==='retry');S.classList.toggle('mistake-canvas',['mistakes','mistake-practice','mistake-complete'].includes(state.route));S.innerHTML=technicalize((views[state.route]||home)()+(isTab?bottomNav():''));if(state.route==='resumes'&&state.resumeReturnRoute==='create-plan')document.querySelectorAll('[data-action="use-resume"]').forEach(button=>{const selected=Number(button.dataset.index)===state.selectedResumeIndex;button.textContent=selected?'已选择':'使用';button.disabled=selected});if(state.route==='practice'&&['connecting','processing'].includes(state.interviewPhase))document.querySelectorAll('[data-action="end-early"],[data-action="replay-question"],[data-action="simulate-disconnect"],[data-action="simulate-question-error"]').forEach(button=>button.setAttribute('disabled',''));S.scrollTop=0;document.querySelectorAll('.route-btn').forEach(b=>b.classList.toggle('active',b.dataset.route===state.route))}
function go(route){const protectedRoutes=!['auth'].includes(route),planRoutes=['interviewers','rounds','sessions','mic-check','practice','report','retry'];if(protectedRoutes&&!state.authenticated){state.intendedRoute=route;state.route='auth';state.authError='请先登录，完成后会返回你刚才访问的页面。';render();return}if(planRoutes.includes(route)&&!state.planSnapshot){const savedPlan=state.plans?.[0];if(savedPlan)activatePlan(savedPlan.id);if(!state.planSnapshot){state.route='home';render();toast('请先创建面试计划');return}}if(route==='resumes'&&['create-plan','profile'].includes(state.route))state.resumeReturnRoute=state.route;if(route!=='practice')state.interviewChatOpen=false;if(route==='home')state.reportFromHistory=false;state.route=route;state.quick=false;state.dialogPanel='';state.liveMode=false;state.bubbleMode=false;state.showTranslation=false;state.mistakeRevealed=false;state.roleVoiceOpen=false;if(route==='role-create'&&state.roleStep>=roleQuestions.length)state.roleStep=0;render()}
function toast(msg){const t=document.getElementById('toast');t.textContent=msg;t.classList.remove('hidden');clearTimeout(toast.timer);toast.timer=setTimeout(()=>t.classList.add('hidden'),1800)}
function submitRoleAnswer(value){const fallback=['旅游聊天伙伴','当地的饭店老板','幽默、热情','像熟悉当地生活的新朋友','点餐、当地建议和旅行闲聊'][state.roleStep];state.roleAnswers[state.roleStep]=(value||fallback).trim();state.recording=false;state.roleTipOpen=false;if(state.roleStep<roleQuestions.length-1){state.roleStep+=1;render()}else{state.roleStep=roleQuestions.length;go('role-generating')}}
document.addEventListener('keydown',e=>{if(e.key==='Enter'&&e.target.id==='role-answer'){e.preventDefault();submitRoleAnswer(e.target.value)}});
