document.addEventListener('input',e=>{const key=e.target.dataset?.draft;if(key&&Object.prototype.hasOwnProperty.call(state.interviewDraft,key))state.interviewDraft[key]=e.target.value});
document.addEventListener('click',e=>{const el=e.target.closest('[data-correction-tab],[data-sub-tab]');if(!el)return;if(el.dataset.correctionTab){document.querySelectorAll('.correction-tab').forEach(t=>t.classList.remove('active'));el.classList.add('active');toast(el.dataset.correctionTab==='grammar'?'查看语法建议':'查看发音建议')}else if(el.dataset.subTab!==undefined){const idx=Number(el.dataset.subTab);const data=[{original:'Hi, I like pizza pizza. I like pizza.',translation:'嗨，我喜欢披萨披萨。我喜欢披萨。',eval:'重复的 "pizza" 让表达显得不够流畅，母语者通常不会这样重复。',suggestions:[{label:'通用',en:'Hi, I really like pizza!',zh:'嗨，我真的很喜欢披萨！',tips:['去掉重复的 pizza 使表达更简洁','加入 really 增强语气']},{label:'口语',en:"I'm totally into pizza!",zh:'我超爱披萨！',tips:['totally into 是地道口语表达','省去 Hi 让对话感更自然']}]},{original:'I really enjoy margherita pizza. It\'s simple but delicious!',translation:'我真的很喜欢玛格丽特披萨。它简单但美味！',eval:'表达自然流畅，语法正确，是很好的表达方式。',suggestions:[{label:'通用',en:'I really enjoy margherita — simple yet delicious!',zh:'我真的很喜欢玛格丽特——简单而美味！',tips:['用破折号连接，节奏更紧凑','yet 比 but 更优雅']},{label:'口语',en:"Margherita's my go-to — can't beat the classics!",zh:'玛格丽特是我首选——经典永不过时！',tips:['go-to 表达首选，很口语化',"can't beat 是地道表达"]}]},{original:'Yes, I maked pizza last weekend with my family. It was very very fun!',translation:'是的，上周末我和家人做了披萨。非常非常有趣！',eval:'maked 是语法错误，made 才是正确形式；very very 重复显得不够地道。',suggestions:[{label:'通用',en:'Yes, I made pizza with my family last weekend. It was so much fun!',zh:'是的，上周末我和家人一起做了披萨。超级有趣！',tips:['make 的过去式是 made，不是 maked','so much fun 比 very very fun 更地道']},{label:'口语',en:'Yeah! Made homemade pizza with the fam last weekend — it was a blast!',zh:'是啊！上周末和家人做了自制披萨——超好玩！',tips:['fam 是 family 的口语缩写','a blast 表示非常好玩']}]}][state.correctionIndex||0];const s=data.suggestions[idx];document.querySelectorAll('.correction-sub-tab').forEach(t=>t.classList.remove('active'));el.classList.add('active');document.getElementById('correctionSuggestion').innerHTML=`<div style="padding:13px 14px"><p style="font-size:15px;font-weight:600;margin:0 0 4px">${s.en}</p><p style="font-size:12px;color:var(--muted);margin:0 0 10px">${s.zh}</p><small style="font-size:11px;color:var(--muted);display:block;margin-bottom:6px">分析</small>${s.tips.map((tip,i)=>`<div style="display:flex;gap:8px;margin-bottom:4px;font-size:12px;line-height:1.6;color:#4B5563"><span style="flex:none;width:18px;height:18px;border-radius:50%;background:var(--surface-2);color:var(--accent);font-size:10px;font-weight:700;display:grid;place-items:center">${i+1}</span><span>${tip}</span></div>`).join('')}</div>`}});
