document.addEventListener('click',e=>{const el=e.target.closest('[data-action]');if(!el)return;const a=el.dataset.action;if(!['start-mistakes','mistake-record','mistake-retry','reveal-mistake','next-mistake'].includes(a))return;e.preventDefault();e.stopImmediatePropagation();if(a==='start-mistakes'){const allItems=savedMistakes(),scope=el.dataset.mistakeScope,mistakeId=el.dataset.mistakeId,type=el.dataset.mistakeType,isConversation=item=>/(角色|场景)/.test(item.source);let items=allItems;if(mistakeId)items=allItems.filter(item=>item.id===mistakeId);else if(scope==='interview')items=allItems.filter(item=>!isConversation(item));else if(scope==='conversation')items=allItems.filter(isConversation);else if(type)items=allItems.filter(item=>item.type===type);state.mistakeReviewIds=items.map(item=>item.id);state.mistakeIndex=0;state.mistakeRecording=false;state.mistakeTranscripts=[];state.mistakeRevealed=false;state.mistakeCompleted=false;if(items.length)go('mistake-practice');else toast('暂无可复习内容')}else if(a==='mistake-record'){if(state.mistakeRecording){const item=reviewMistakes()[state.mistakeIndex];state.mistakeRecording=false;state.mistakeTranscripts[state.mistakeIndex]=item?.answer||item?.original||'';render();toast('语音已转写')}else{state.mistakeRecording=true;state.mistakeRevealed=false;render();toast('正在聆听…')}}else if(a==='mistake-retry'){state.mistakeRecording=false;state.mistakeTranscripts[state.mistakeIndex]='';state.mistakeRevealed=false;render()}else if(a==='reveal-mistake'){state.mistakeRecording=false;state.mistakeRevealed=true;render()}else{const items=reviewMistakes();if(state.mistakeIndex>=items.length-1){state.mistakeCompleted=true;state.mistakeRecording=false;state.mistakeRevealed=false;go('mistake-complete');toast('本轮错题复盘已完成')}else{state.mistakeIndex+=1;state.mistakeRecording=false;state.mistakeRevealed=false;render();toast('已进入下一题')}}},true);
